import boto3
import os
import logging
from botocore.exceptions import ClientError

# Set up logging
logger = logging.getLogger()
logger.setLevel(logging.INFO)

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')

def lambda_handler(event, context):
    try:
        # Extract bucket name and object key from the event
        bucket_name = event['Records'][0]['s3']['bucket']['name']
        object_key = event['Records'][0]['s3']['object']['key']
        
        # Read the image from S3
        response = s3_client.get_object(Bucket=bucket_name, Key=object_key)
        image_data = response['Body'].read()
        
        # Process the image (placeholder for actual image processing logic)
        processed_image_data = image_data  # Replace with actual processing
        
        # Write the processed image back to S3
        processed_key = f"processed/{object_key}"
        s3_client.put_object(Bucket=bucket_name, Key=processed_key, Body=processed_image_data)
        
        # Send a notification via SNS
        sns_topic_arn = os.environ['SNS_TOPIC_ARN']
        sns_client.publish(
            TopicArn=sns_topic_arn,
            Message=f"Image {object_key} processed and stored as {processed_key}",
            Subject="Image Processing Complete"
        )
        
        # Log to CloudWatch
        logger.info(f"Successfully processed image {object_key} and stored as {processed_key}")
        
    except ClientError as e:
        logger.error(f"Error processing image: {e}")
        raise

